package entity_test

import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchBFA050A9(t *testing.T) {
	tests := []struct {
		name  string
		order entity.Order
		want  float64
	}{
		{
			name:  "empty items",
			order: entity.Order{},
			want:  0,
		},
		{
			name: "zero quantity",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 0, Price: 10.0},
				},
			},
			want: 0,
		},
		{
			name: "negative price",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 2, Price: -5.0},
				},
			},
			want: -10.0,
		},
		{
			name: "large quantity",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 1_000_000, Price: 9.99},
				},
			},
			want: 9_990_000.0,
		},
		{
			name: "mixed items",
			order: entity.Order{
				Items: []entity.OrderItem{
					{Quantity: 2, Price: 3.5},
					{Quantity: 0, Price: 100.0},
					{Quantity: 1, Price: -2.0},
				},
			},
			want: 5.0,
		},
	}

	const epsilon = 1e-9

	for _, tc := range tests {
		t.Run(tc.name, func(t *testing.T) {
			got := tc.order.CalculateTotal()
			if math.Abs(got-tc.want) > epsilon {
				t.Errorf("CalculateTotal() = %v, want %v", got, tc.want)
			}
		})
	}
}

