package entity_test

import (
	"strings"
	"testing"
	"unicode/utf8"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchE104B40A(t *testing.T) {
	// Determine the max runes limit used by Summary.
	long := strings.Repeat("a", 1000)
	ni := entity.NewsItem{Content: long}
	summary := ni.Summary()
	limit := len([]rune(summary))
	hasEllipsis := false
	if limit > 0 && []rune(summary)[limit-1] == '…' {
		hasEllipsis = true
		limit--
	}

	type testCase struct {
		name  string
		input string
		want  string
	}
	tests := []testCase{
		{
			name:  "exact limit with multibyte runes",
			input: strings.Repeat("😀", limit), // each emoji is one rune (4‑byte UTF‑8)
			// expect no truncation, no ellipsis
			want: strings.Repeat("😀", limit),
		},
		{
			name:  "exceeds limit by one emoji",
			input: strings.Repeat("😀", limit+1),
			// expect truncation to limit runes, possibly with ellipsis
			want: func() string {
				base := strings.Repeat("😀", limit)
				if hasEllipsis {
					return base + "…"
				}
				return base
			}(),
		},
		{
			name:  "mixed CJK and emoji at boundary",
			input: func() string {
				// Build a string where the last rune inside the limit is a CJK character,
				// and the next rune (which should be cut off) is an emoji.
				var sb strings.Builder
				// fill limit-1 runes with simple ASCII
				sb.WriteString(strings.Repeat("a", limit-1))
				// add a CJK rune (one rune)
				sb.WriteString("你") // Chinese character
				// add an extra emoji that exceeds the limit
				sb.WriteString("😀")
				return sb.String()
			}(),
			want: func() string {
				var sb strings.Builder
				sb.WriteString(strings.Repeat("a", limit-1))
				sb.WriteString("你")
				if hasEllipsis {
					return sb.String() + "…"
				}
				return sb.String()
			}(),
		},
	}

	for _, tc := range tests {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			ni := entity.NewsItem{Content: tc.input}
			got := ni.Summary()

			if got != tc.want {
				t.Fatalf("unexpected summary.\nwant: %q\n got: %q", tc.want, got)
			}
			if !utf8.ValidString(got) {
				t.Fatalf("resulting summary is not valid UTF-8: %q", got)
			}
			// Ensure the result does not exceed the limit (excluding possible ellipsis)
			runes := []rune(got)
			if hasEllipsis && len(runes) > 0 && runes[len(runes)-1] == '…' {
				runes = runes[:len(runes)-1]
			}
			if len(runes) > limit {
				t.Fatalf("summary exceeds max runes: have %d, limit %d", len(runes), limit)
			}
		})
	}
}

