package entity_test

// CHOICE: Product.ApplyDiscount — edge cases for discount validation not covered
import (
	"math"
	"testing"

	"github.com/nikita-rulenko/heisenbug-portal/internal/entity"
)

func TestUnitBenchC0B8A596(t *testing.T) {
	const eps = 0.1

	tests := []struct {
		name       string
		price      float64
		discount   float64
		wantPrice  float64
		wantErr    bool
	}{
		{
			name:      "no discount",
			price:     100,
			discount:  0,
			wantPrice: 100,
			wantErr:   false,
		},
		{
			name:      "half discount",
			price:     200,
			discount:  50,
			wantPrice: 100,
			wantErr:   false,
		},
		{
			name:      "full discount",
			price:     150,
			discount:  100,
			wantPrice: 0,
			wantErr:   false,
		},
		{
			name:      "negative discount",
			price:     100,
			discount:  -10,
			wantPrice: 0,
			wantErr:   true,
		},
		{
			name:      "over discount",
			price:     100,
			discount:  150,
			wantPrice: 0,
			wantErr:   true,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			p := entity.Product{Price: tt.price}
			err := p.ApplyDiscount(tt.discount)

			if (err != nil) != tt.wantErr {
				t.Fatalf("expected error %v, got %v", tt.wantErr, err)
			}
			if !tt.wantErr {
				if math.Abs(p.Price-tt.wantPrice) > eps {
					t.Fatalf("price after discount = %v, want %v (tolerance %v)", p.Price, tt.wantPrice, eps)
				}
			}
		})
	}
}
